import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import { MultimediaCreator } from './components/MultimediaCreator';
import ChatBot from './components/ChatBot';
import Intro from './components/Intro';
import Analytics from './components/Analytics';
import Scheduler from './components/Scheduler';
import type { ActiveView, XUserProfile } from './types';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ActiveView>('content');
  const [isLoading, setIsLoading] = useState(true);
  const [token, setToken] = useState<string | null>(localStorage.getItem('x-token'));
  const [userProfile, setUserProfile] = useState<XUserProfile | null>(null);

  useEffect(() => {
    setTimeout(() => setIsLoading(false), 1500);
  }, []);

  const handleLoginSuccess = (newToken: string, profile: XUserProfile) => {
    setToken(newToken);
    setUserProfile(profile);
    localStorage.setItem('x-token', newToken);
    if(profile.handle) localStorage.setItem('x-username', profile.handle.replace('@', ''));
  };

  const renderActiveView = () => {
    switch (activeView) {
      case 'content':
        return <Dashboard />;
      case 'multimedia':
        return <MultimediaCreator />;
      case 'analytics':
        return <Analytics onLoginSuccess={handleLoginSuccess} initialToken={token} userProfile={userProfile} />;
      case 'calendar':
        return <Scheduler />;
      default:
        return <Dashboard />;
    }
  };

  if (isLoading) {
    return <Intro />;
  }

  return (
    <div className="min-h-screen bg-bg-primary transition-colors duration-300">
      <Header 
        activeView={activeView} 
        setActiveView={setActiveView}
        conversations={[]}
        activeConversationId={null}
        onSelectConversation={() => {}}
        onNewConversation={() => {}}
        onDeleteConversation={() => {}}
      />
      <main className="pt-28 pb-8 px-4 sm:px-8">
        {renderActiveView()}
      </main>
      <ChatBot />
    </div>
  );
};

export default App;

