import React, { useState, useRef, useEffect } from 'react';
import type { ChatMessage } from '../types';
import LoaderIcon from './icons/LoaderIcon';
import PaperclipIcon from './icons/PaperclipIcon';

interface ChatHistoryProps {
  messages: ChatMessage[];
  onSendMessage: (message: string, file?: { data: string; mimeType: string; name: string }) => void;
  isLoading: boolean;
  fileToBase64: (file: Blob) => Promise<{data: string, mimeType: string, name: string}>;
}

const ChatHistory: React.FC<ChatHistoryProps> = ({ messages, onSendMessage, isLoading, fileToBase64 }) => {
  const [input, setInput] = useState('');
  const chatEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading]);

  const handleSend = () => {
    if (input.trim() && !isLoading) {
      onSendMessage(input.trim());
      setInput('');
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
      const file = event.target.files?.[0];
      if (file) {
          const fileData = await fileToBase64(file);
          onSendMessage(input, fileData);
          setInput('');
      }
      if (fileInputRef.current) {
          fileInputRef.current.value = '';
      }
  };

  return (
    <div className="animate-fade-in flex flex-col h-full rounded-b-xl">
        <div ref={chatEndRef} className="flex-grow p-4 space-y-4 overflow-y-auto">
            {messages.map((msg, index) => (
                <div key={index} className={`flex items-end gap-2 ${msg.author === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[80%] p-3 rounded-2xl ${msg.author === 'user' ? 'bg-accent-primary text-white rounded-br-none' : 'bg-slate-200 text-slate-800 rounded-bl-none'}`}>
                        <p className="text-sm whitespace-pre-wrap">{msg.content}</p>
                        {msg.author === 'ai' && msg.sources && msg.sources.length > 0 && (
                            <div className="mt-3 pt-2 border-t border-slate-300">
                                <h4 className="text-xs font-bold text-slate-500 mb-1">Fuentes</h4>
                                <div className="space-y-1 max-h-24 overflow-y-auto">
                                    {msg.sources.map((source, i) => (
                                        <a key={i} href={source.web.uri} target="_blank" rel="noopener noreferrer" className="block p-1.5 bg-slate-50 hover:bg-slate-100 rounded-md">
                                            <p className="text-xs font-semibold text-accent-primary truncate">{source.web.title || source.web.uri}</p>
                                        </a>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            ))}
            {isLoading && (
                <div className="flex justify-start">
                     <div className="max-w-[80%] p-3 rounded-2xl bg-slate-200 text-slate-800 rounded-bl-none">
                        <LoaderIcon className="h-5 w-5" />
                    </div>
                </div>
            )}
        </div>
        <div className="p-2 border-t border-slate-200 mt-auto bg-white rounded-b-xl">
            <div className="flex items-center gap-1 bg-slate-100 border border-slate-200 rounded-xl p-1.5">
                <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" />
                <button onClick={() => fileInputRef.current?.click()} disabled={isLoading} className="p-2 hover:bg-slate-200 rounded-full text-slate-500 transition-colors">
                    <PaperclipIcon className="h-5 w-5"/>
                </button>
                <textarea
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    onKeyDown={handleKeyPress}
                    placeholder="Inicia una conversación con la IA..."
                    className="flex-grow bg-transparent focus:outline-none transition resize-none text-sm text-slate-900 placeholder:text-slate-500 px-2 py-2"
                    rows={1}
                    disabled={isLoading}
                />
                <button 
                    onClick={handleSend}
                    disabled={isLoading || !input.trim()}
                    className="self-center ml-auto px-4 py-2 rounded-lg font-bold transition-colors text-sm bg-white text-black border border-black shadow-sm hover:bg-slate-100 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                    Enviar
                </button>
            </div>
        </div>
    </div>
  );
};

export default ChatHistory;

import { GoogleGenAI, Type, GenerateContentResponse, Chat, Modality, GenerateImagesResponse, Operation } from "@google/genai";
import type { Source, Tweet, BrandVoiceProfile, TrendingTopic, XUserProfile } from "../types";

// Helper to get a Gemini client instance
const getGeminiClient = () => {
    // API Key is injected by the execution environment.
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        throw new Error("Gemini API key is not configured in the environment.");
    }
    return new GoogleGenAI({ apiKey });
};

/**
 * A wrapper function to add retry logic with exponential backoff to API calls.
 */
export const withRetry = async <T>(apiCall: () => Promise<T>, retries = 1, delay = 1000): Promise<T> => {
    for (let i = 0; i <= retries; i++) {
        try {
            return await apiCall();
        } catch (error) {
            const isLastAttempt = i === retries;
            const errorMessage = error instanceof Error ? error.message.toLowerCase() : String(error).toLowerCase();

            // Critical: Fail fast on permission errors or not found
            if (errorMessage.includes("permission denied") || 
                errorMessage.includes("403") || 
                errorMessage.includes("not found") || 
                errorMessage.includes("404")) {
                 throw error; 
            }

            const isRetryable = errorMessage.includes("xhr error") || 
                                errorMessage.includes("rpc failed") || 
                                errorMessage.includes("500") ||
                                errorMessage.includes("429") || 
                                errorMessage.includes("rate-limited") || 
                                errorMessage.includes("overloaded") ||
                                errorMessage.includes("at capacity");

            if (isRetryable && !isLastAttempt) {
                console.warn(`API call failed (attempt ${i + 1}/${retries + 1}). Retrying in ${delay}ms...`, error);
                await new Promise(res => setTimeout(res, delay));
                delay *= 2; 
            } else {
                throw error; 
            }
        }
    }
    throw new Error("API call failed after all retries.");
};


interface FilePart {
    mimeType: string;
    data: string; // base64 encoded
}

export const getFriendlyErrorMessage = (error: unknown, contextAction: string): string => {
    console.error(`Error al ${contextAction} con Gemini:`, error);
    let friendlyMessage = `No se pudo ${contextAction} debido a un problema inesperado.`;

    if (error instanceof Error) {
        let errorMessage = error.message;

        // Try to parse JSON error message
        try {
            const jsonStart = errorMessage.indexOf('{');
            const jsonEnd = errorMessage.lastIndexOf('}');
            if (jsonStart !== -1 && jsonEnd !== -1) {
                const jsonStr = errorMessage.substring(jsonStart, jsonEnd + 1);
                const parsed = JSON.parse(jsonStr);
                if (parsed.error && parsed.error.message) {
                    errorMessage = parsed.error.message;
                }
            }
        } catch (e) { /* ignore parse error */ }

        const lowerMessage = errorMessage.toLowerCase();

        if (lowerMessage.includes("api key") || lowerMessage.includes("clave api") || lowerMessage.includes("authentication")) {
            friendlyMessage = `Error de Clave API: La clave API de Gemini proporcionada parece ser inválida.`;
        } else if (lowerMessage.includes('requested entity was not found') || lowerMessage.includes('404')) {
            friendlyMessage = `Error de Modelo (404): El modelo solicitado no está disponible.`;
        } else if (lowerMessage.includes("permission denied") || lowerMessage.includes("403")) {
            friendlyMessage = `Error de Permiso (403): Tu clave API no tiene acceso al modelo solicitado. Verifica que la API de Gemini esté habilitada en tu proyecto de Google Cloud.`;
        } else if (lowerMessage.includes("unsupported mime type") || lowerMessage.includes("invalid_argument")) {
             friendlyMessage = `Error de Formato: El tipo de archivo proporcionado no es compatible. Usa PDF, Imágenes o Texto plano.`;
        } else if (lowerMessage.includes("la ia respondió con texto")) {
             friendlyMessage = `Error de Generación: La IA no generó una imagen visual, sino texto. Intenta simplificar el prompt.`;
        } else if (lowerMessage.includes("rpc failed") || lowerMessage.includes("xhr error")) {
             friendlyMessage = `Error de Conexión (500): Hubo un problema al comunicar con los servidores de Google. Verifica tu conexión.`;
        } else {
             friendlyMessage = `Ocurrió un error inesperado: ${errorMessage}`;
        }
    } else {
        friendlyMessage = `Ocurrió un error desconocido: ${String(error)}`;
    }
    return friendlyMessage;
}

const handleGenerationError = (error: unknown, contextNoun: string): never => {
    const friendlyMessage = getFriendlyErrorMessage(error, `generar ${contextNoun}`);
    throw new Error(friendlyMessage);
}

// Helper to validate and prepare file parts
const prepareFilePart = (file: FilePart) => {
    if (file.mimeType === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' || 
        file.mimeType === 'application/msword') {
        throw new Error("El formato Word (.doc/.docx) no es compatible directamente. Por favor, exporta tu documento a PDF o copia el contenido a un archivo de texto (.txt).");
    }

    if (file.mimeType.startsWith('text/') || file.mimeType === 'application/json' || file.mimeType === 'application/xml' || file.mimeType === 'text/markdown' || file.mimeType === 'text/csv') {
         try {
            const binaryString = atob(file.data);
            const bytes = new Uint8Array(binaryString.length);
            for (let i = 0; i < binaryString.length; i++) {
                bytes[i] = binaryString.charCodeAt(i);
            }
            const decodedText = new TextDecoder().decode(bytes);
            return { text: `Contenido del archivo:\n${decodedText}` };
        } catch (e) {
            console.warn("Error decoding text file, falling back to inlineData", e);
            return { inlineData: { mimeType: file.mimeType, data: file.data } };
        }
    }

    const allowedPrefixes = ['image/', 'audio/', 'video/', 'application/pdf'];
    if (allowedPrefixes.some(prefix => file.mimeType.startsWith(prefix))) {
         return { inlineData: { mimeType: file.mimeType, data: file.data } };
    }

    throw new Error(`Tipo de archivo no soportado (${file.mimeType}). Por favor usa PDF, Imágenes, Audio o Texto.`);
};

const TEXT_MODEL = 'gemini-3-flash-preview';
const IMAGE_MODEL = 'gemini-2.5-flash-image'; 

export const summarizeFileContent = async (file: FilePart): Promise<string> => {
    try {
        const ai = getGeminiClient();
        const fileContentPart = prepareFilePart(file);
        const parts: any[] = [
            fileContentPart,
            { text: "Resume los puntos clave de este documento en un párrafo conciso, adecuado como punto de partida para crear una publicación en redes sociales. Céntrate en la información más importante." }
        ];

        const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: TEXT_MODEL,
            contents: { parts }
        }));
        return response.text;
    } catch (error) {
        handleGenerationError(error, 'resumen');
        return '';
    }
};

export const getSystemInstructionTweet = (audience?: string, tone?: string, format?: string, keywords?: string, brandVoice?: BrandVoiceProfile) => {
     let toneInstruction = tone ? `Tono: ${tone}.` : `Tono: Profesional y atractivo.`;
     let extraInstructions = '';
    if (format) extraInstructions += ` Formato: ${format}.`;
    if (keywords) extraInstructions += ` Keywords: "${keywords}".`;

    let brandVoiceInstruction = '';
    if (brandVoice && (brandVoice.toneAndStyle || brandVoice.targetAudience)) {
        brandVoiceInstruction = `VOZ DE MARCA: ${brandVoice.toneAndStyle}. Público: ${brandVoice.targetAudience}.`;
    }

    return `Experto en redes sociales. Crea un tuit viral (max 275 chars).
    ${toneInstruction}
    ${brandVoiceInstruction}
    ${extraInstructions}
    Si hay enlace/archivo, úsalo. Si es corrección, mejora el texto.
    SOLO devuelve el texto del tuit.`;
}

export const getSystemInstructionThread = (audience?: string, tone?: string, format?: string, keywords?: string, brandVoice?: BrandVoiceProfile) => {
    let brandVoiceInstruction = '';
    if (brandVoice) {
        brandVoiceInstruction = `VOZ DE MARCA: ${brandVoice.toneAndStyle}. Público: ${brandVoice.targetAudience}.`;
    }

    return `Experto en hilos de X. Crea un hilo viral.
    ${brandVoiceInstruction}
    Devuelve SOLO JSON: {"thread": ["tuit 1", "tuit 2"]}.`;
};

export const generateTweet = async (
    prompt: string,
    source?: Source,
    audience?: string,
    file?: FilePart,
    tone?: string,
    format?: string,
    keywords?: string,
    brandVoice?: BrandVoiceProfile,
    useWebSearch?: boolean
): Promise<string> => {
    try {
        const ai = getGeminiClient();
        const systemInstruction = getSystemInstructionTweet(audience, tone, format, keywords, brandVoice);
        const parts: any[] = [];
        if (file) parts.push(prepareFilePart(file));
        parts.push({ text: prompt });

        const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: TEXT_MODEL,
            contents: { parts },
            config: {
                systemInstruction,
                tools: (useWebSearch || prompt.toLowerCase().includes('investiga')) ? [{ googleSearch: {} }] : undefined,
            }
        }));

        return response.text.trim();
    } catch (error) {
        handleGenerationError(error, 'tuit');
        return '';
    }
};

export const generateTweetThread = async (
    prompt: string,
    source?: Source,
    audience?: string,
    file?: FilePart,
    tone?: string,
    format?: string,
    keywords?: string,
    brandVoice?: BrandVoiceProfile,
    useWebSearch?: boolean
): Promise<string[]> => {
    try {
        const ai = getGeminiClient();
        const systemInstruction = getSystemInstructionThread(audience, tone, format, keywords, brandVoice);
        const parts: any[] = [];
        if (file) parts.push(prepareFilePart(file));
        parts.push({ text: prompt });

        const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: TEXT_MODEL,
            contents: { parts },
            config: {
                systemInstruction,
                responseMimeType: 'application/json',
                tools: (useWebSearch || prompt.toLowerCase().includes('investiga')) ? [{ googleSearch: {} }] : undefined,
            }
        }));

        let jsonStr = response.text.trim();
        const jsonMatch = jsonStr.match(/```json\n?([\s\S]*?)\n?```/);
        if (jsonMatch && jsonMatch[1]) jsonStr = jsonMatch[1];
        else {
             const firstBrace = jsonStr.indexOf('{');
             const lastBrace = jsonStr.lastIndexOf('}');
             if (firstBrace !== -1) jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
        }

        const result = JSON.parse(jsonStr);
        if (result.thread && Array.isArray(result.thread)) return result.thread;
        throw new Error("Formato de hilo inválido.");

    } catch (error) {
        handleGenerationError(error, 'hilo de tuits');
        return [];
    }
};

export const regenerateTweet = async (tweetContent: string): Promise<string> => {
    try {
        const ai = getGeminiClient();
        const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: TEXT_MODEL,
            contents: { parts: [{ text: `Mejora este tuit (max 275 chars): "${tweetContent}"` }] },
        }));
        return response.text.trim();
    } catch (error) {
        handleGenerationError(error, 'regeneración');
        return '';
    }
};

export const generateImage = async (prompt: string, aspectRatio: string = '1:1', referenceImages?: { data: string; mimeType: string }[]): Promise<{ images: string[], model: string }> => {
    const ai = getGeminiClient();
    const ratioMap: Record<string, string> = { '1:1': '1:1', '16:9': '16:9', '9:16': '9:16', '4:3': '4:3', '3:4': '3:4' };
    const validRatio = ratioMap[aspectRatio] || '1:1';

    let finalPrompt = prompt;
    if (referenceImages && referenceImages.length > 0) {
        finalPrompt = `Use the provided image(s) as reference. ${prompt}`;
    }

    try {
        const parts: any[] = [];
        if (referenceImages && referenceImages.length > 0) {
            referenceImages.forEach(img => {
                parts.push({ inlineData: { data: img.data, mimeType: img.mimeType } });
            });
        }
        parts.push({ text: finalPrompt });

        const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: IMAGE_MODEL,
            contents: { parts },
            config: {
                imageConfig: { aspectRatio: validRatio as any }
            }
