            <div className="mb-6 animate-fade-in">
                <label className="block text-sm font-bold text-text-secondary mb-2">
                    {activeCategory === 'mix' ? 'Imágenes para Mezclar (Mín. 2)' : activeCategory === 'edit' ? 'Imagen a Editar (Mín. 1)' : 'Imagen de Referencia'}
                </label>

                {filePreviews.length > 0 && (
                    <div className="grid grid-cols-3 gap-2 mb-3">
                        {filePreviews.map((src, index) => (
                            <div key={index} className="relative aspect-square rounded-lg overflow-hidden border border-border-primary group">
                                <img src={src} alt="preview" className="w-full h-full object-cover" />
                                <button onClick={() => removeFile(index)} className="absolute top-1 right-1 bg-black/60 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity">
                                    <TrashIcon className="w-3 h-3"/>
                                </button>
                            </div>
                        ))}
                        {(activeCategory === 'mix' || (activeCategory !== 'edit' && filePreviews.length < 4)) && (
                            <button onClick={() => fileInputRef.current?.click()} className="aspect-square rounded-lg border-2 border-dashed border-border-primary flex items-center justify-center hover:bg-bg-primary text-text-secondary hover:text-accent-primary transition-colors">
                                <UploadIcon className="w-6 h-6"/>
                            </button>
                        )}
                    </div>
                )}

                {filePreviews.length === 0 && (
                <div onClick={() => fileInputRef.current?.click()} className="group border-2 border-dashed border-border-primary hover:border-accent-primary rounded-xl p-6 text-center cursor-pointer transition-all duration-300 hover:bg-bg-primary">
                    <div className="flex flex-col items-center gap-2 text-text-secondary group-hover:text-accent-primary">
                        <UploadIcon className="w-6 h-6"/>
                        <span className="text-xs font-bold uppercase tracking-wide">Subir Imagen</span>
                    </div>
                </div>
                )}
                <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept="image/*" multiple={activeCategory !== 'edit'} />
            </div>

            <div className="mb-6">
              <div className="flex justify-between items-end mb-2">
                <label className="text-sm font-bold text-text-secondary">
                    {activeCategory === 'edit' ? '¿Qué quieres cambiar?' : 'Descripción del diseño'}
                </label>
                <button onClick={handleIdeaGeneration} disabled={isLoadingIdeas} className="text-xs flex items-center gap-1 text-accent-primary hover:text-accent-secondary font-bold transition-colors disabled:opacity-50">
                    <SparklesIcon className="w-3 h-3"/> {isLoadingIdeas ? 'Pensando...' : 'Sugerir Idea'}
                </button>
              </div>
              <textarea
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
                placeholder={activeCategory === 'edit' ? "Ej: Añade un filtro retro, elimina a la persona en el fondo..." : "Ej: Un paisaje futurista..."}
                className="w-full bg-bg-primary border border-border-primary rounded-xl p-4 focus:ring-2 focus:ring-accent-primary focus:outline-none transition min-h-[100px] resize-none text-text-primary placeholder:text-slate-500"
              />

              {activeCategory === 'edit' && uploadedFiles.length > 0 && (
                  <div className="mt-4">
                      <p className="text-xs font-bold text-text-secondary mb-2">Acciones Rápidas:</p>
                      <div className="flex flex-wrap gap-2">
                          {EDIT_PRESETS.map((preset, i) => (
                              <button 
                                key={i} 
                                onClick={() => handleGenerate(preset.prompt)}
                                disabled={isGenerating}
                                className="text-[10px] bg-bg-primary border border-border-primary hover:border-accent-primary text-text-secondary hover:text-text-primary px-3 py-1.5 rounded-full transition-all"
                              >
                                  {preset.label}
                              </button>
                          ))}
                      </div>
                  </div>
              )}
            </div>

            <div className="mb-8">
                <label className="block text-sm font-bold text-text-secondary mb-3">Relación de Aspecto</label>
                <div className="grid grid-cols-5 gap-2">
                    {ASPECT_RATIOS.map((ratio) => (
                    <button key={ratio} onClick={() => setAspectRatio(ratio)} className={`flex flex-col items-center justify-center p-2 rounded-lg border transition-all duration-200 ${aspectRatio === ratio ? 'bg-accent-primary/10 border-accent-primary text-accent-primary ring-1 ring-accent-primary' : 'border-border-primary text-text-secondary hover:bg-bg-primary hover:border-text-secondary'}`}>
                        <span className="text-[10px] font-bold mb-1.5">{ratio}</span>
                        <div className={`border-2 rounded-sm ${aspectRatio === ratio ? 'border-accent-primary bg-accent-primary' : 'border-current'}`} style={{ width: ratio === '16:9' ? '24px' : ratio === '9:16' ? '14px' : ratio === '4:3' ? '20px' : ratio === '3:4' ? '16px' : '18px', height: ratio === '16:9' ? '14px' : ratio === '9:16' ? '24px' : ratio === '4:3' ? '16px' : ratio === '3:4' ? '20px' : '18px', }}></div>
                    </button>
                    ))}
                </div>
            </div>

            <button onClick={() => handleGenerate()} disabled={isGenerating || (!prompt && activeCategory !== 'edit' && activeCategory !== 'mix') || (activeCategory === 'edit' && uploadedFiles.length === 0) || (activeCategory === 'mix' && uploadedFiles.length < 2)} className="w-full py-4 bg-accent-primary text-white rounded-xl font-bold hover:bg-accent-secondary transition-all shadow-lg shadow-accent-primary/20 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2 transform hover:-translate-y-0.5 active:translate-y-0">
              {isGenerating ? <LoaderIcon className="w-5 h-5"/> : <SparklesIcon className="w-5 h-5"/>}
              {isGenerating ? 'Procesando...' : activeCategory === 'edit' ? 'Aplicar Edición' : 'Generar Diseño'}
            </button>

            {generationError && <div className="mt-4 p-3 bg-red-50 border border-red-100 text-red-500 text-sm rounded-lg flex items-start gap-2"><span className="font-bold">Error:</span> {generationError}</div>}
          </div>
        </div>

        <div className="lg:col-span-7">
          <div className="bg-bg-secondary border border-border-primary rounded-xl p-6 min-h-[500px] flex flex-col items-center justify-center relative shadow-lg overflow-hidden">
            {isGenerating ? (
                <div className="text-center animate-pulse">
                    <div className="relative w-24 h-24 mx-auto mb-6">
                        <div className="absolute inset-0 border-4 border-accent-primary/20 rounded-full"></div>
                        <div className="absolute inset-0 border-4 border-accent-primary rounded-full border-t-transparent animate-spin"></div>
                        <SparklesIcon className="absolute inset-0 m-auto w-8 h-8 text-accent-primary animate-bounce"/>
                    </div>
                    <h3 className="text-xl font-bold text-text-primary">IA en acción...</h3>
                </div>
            ) : generatedImage ? (
                <div className="relative w-full h-full flex flex-col items-center animate-fade-in group">
                    <div className="relative rounded-lg shadow-2xl overflow-hidden border border-border-primary bg-bg-primary">
                        <img src={generatedImage} alt="Generada por IA" className="max-h-[600px] w-full object-contain" />
                        <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                             <button onClick={() => handleGenerate()} className="p-3 bg-white/90 backdrop-blur text-slate-900 rounded-full shadow-lg hover:scale-110 transition-transform">
                                <RefreshIcon className="w-5 h-5"/>
                            </button>
                        </div>
                    </div>

                    <div className="flex gap-4 mt-6 w-full max-w-md justify-center">
                        <button onClick={handleSendToEdit} className="flex-1 flex items-center justify-center gap-2 py-3 bg-bg-primary text-text-primary border border-border-primary rounded-xl font-bold hover:bg-bg-secondary transition-colors">
                            <RefreshIcon className="w-4 h-4" /> Seguir Editando
                        </button>
                        <a href={downloadUrl || '#'} download={`twixai-${activeCategory}.png`} className={`flex-1 flex items-center justify-center gap-2 py-3 bg-accent-primary text-white rounded-xl font-bold hover:bg-accent-secondary transition-colors shadow-sm ${!downloadUrl ? 'opacity-50 cursor-not-allowed' : ''}`}>
                            <DownloadIcon className="w-5 h-5"/> Descargar
                        </a>
                    </div>
                </div>
            ) : (
                <div className="text-center text-text-secondary max-w-xs">
                    <div className="w-20 h-20 bg-bg-primary rounded-full flex items-center justify-center mx-auto mb-4 border border-border-primary">
                        <CameraIcon className="w-8 h-8 opacity-50"/>
                    </div>
                    <p className="font-medium">Tu creación aparecerá aquí.</p>
                </div>
            )}
          </div>
        </div>
      </div>

      <style>{`
        .animate-fade-in { animation: fadeIn 0.5s ease-out forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import type { Chat } from "@google/genai";
import { createContentChatSession, regenerateTweet, generateImage, generateVideo, generateCreativeMediaPrompt } from '../services/geminiService';
import type { XUserProfile, EditableTweet, BrandVoiceProfile, ChatMessage } from '../types';
import TweetPreview from './TweetPreview';
import GenerationStatus from './GenerationStatus';
import BrandVoiceModal from './BrandVoiceModal';
import ChatHistory from './ChatHistory';
import LogoIcon from './icons/LogoIcon';
import PlusIcon from './icons/PlusIcon';
import SparklesIcon from './icons/SparklesIcon';
import LoaderIcon from './icons/LoaderIcon';

const DEFAULT_USER: XUserProfile = {
  id: 'user-cryptomaso',
  name: 'cryptomaso',
  handle: '@cryptomaso',
  avatarUrl: `data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='%23657786'%3E%3Cpath d='M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z'/%3E%3C/svg%3E`,
  verified: true
};

const fileToBase64 = (file: Blob): Promise<{data: string, mimeType: string, name: string}> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => {
            const result = reader.result as string;
            const name = file instanceof File ? file.name : 'audio.webm';
            resolve({ data: result.split(',')[1], mimeType: file.type, name });
        };
        reader.onerror = error => reject(error);
    });
}

const Dashboard: React.FC = () => {
  const [tweets, setTweets] = useState<EditableTweet[]>([{ id: `tweet-0`, content: '', media: null, isLoadingMedia: false, isCopied: false, isRegenerating: false }]);
  const [isLoading, setIsLoading] = useState(false);
  const [generationStatus, setGenerationStatus] = useState<{ title: string; steps: string[]; currentStep: number; error: string | null; } | null>(null);

  const [isBrandVoiceModalOpen, setIsBrandVoiceModalOpen] = useState(false);
  const [brandVoiceProfile, setBrandVoiceProfile] = useState<BrandVoiceProfile | null>(null);

  const [chatSession, setChatSession] = useState<Chat | null>(null);
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([
    {
      author: 'ai',
      content: "¡Hola! Soy tu asistente de IA para la creación de contenido. ¿Qué te gustaría crear hoy? Puedes pedirme un tuit, un hilo, o darme una idea y la desarrollaremos juntos."
    }
  ]);
  const [isChatLoading, setIsChatLoading] = useState(false);

  const [isMediaPromptModalOpen, setIsMediaPromptModalOpen] = useState(false);
  const [isGeneratingMediaPrompt, setIsGeneratingMediaPrompt] = useState(false);
  const [mediaPrompt, setMediaPrompt] = useState('');
  const [mediaAspectRatio, setMediaAspectRatio] = useState('1:1');
  const [mediaGenerationTarget, setMediaGenerationTarget] = useState<{type: 'image' | 'video', index: number, isEdit: boolean} | null>(null);
  const [mediaTargetIndex, setMediaTargetIndex] = useState<number | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const tweetPreviewRefs = useRef<(HTMLDivElement | null)[]>([]);

  useEffect(() => {
    const savedProfile = localStorage.getItem('twixai-brand-voice');
    if (savedProfile) {
      setBrandVoiceProfile(JSON.parse(savedProfile));
    }
  }, []);

  useEffect(() => {
    setChatSession(createContentChatSession(brandVoiceProfile || undefined));
  }, [brandVoiceProfile]);

  const handleSaveBrandVoice = (profile: BrandVoiceProfile) => {
    setBrandVoiceProfile(profile);
    localStorage.setItem('twixai-brand-voice', JSON.stringify(profile));
  };

  const handleTweetChange = (index: number, value: string) => {
    const newTweets = [...tweets];
    newTweets[index].content = value;
    setTweets(newTweets);
  };

  const addTweetToThread = () => {
    setTweets([...tweets, { id: `tweet-${Date.now()}`, content: '', media: null, isLoadingMedia: false, isCopied: false, isRegenerating: false }]);
  };

  const handleSendMessage = async (message: string, file?: { data: string; mimeType: string; name: string }) => {
    if ((!message || message.trim() === '') && !file) return;

    const userMessageContent = file ? `${message}\n\n[Archivo adjunto: ${file.name}]` : message;
    const userMessage: ChatMessage = { author: 'user', content: userMessageContent };
    setChatMessages(prev => [...prev, userMessage]);
    setIsChatLoading(true);

    try {
        if (!chatSession) throw new Error("La sesión de chat no está inicializada.");

        const parts: any[] = [{ text: message }];
        if (file) {
            parts.push({ inlineData: { mimeType: file.mimeType, data: file.data } });
        }

        const response = await chatSession.sendMessage({ message: parts });
        const assistantResponse = response.text;

        setChatMessages(prev => [...prev, { author: 'ai', content: assistantResponse }]);

        let parsedTweets: string[] = [];
        const isThread = assistantResponse.includes('"thread":');

        if (isThread) {
            try {
                let jsonStr = assistantResponse.trim();
                const jsonMatch = jsonStr.match(/```json\n?([\s\S]*?)\n?```/);
                if (jsonMatch) {
                    jsonStr = jsonMatch[1];
                }
                const result = JSON.parse(jsonStr);
                if (result.thread && Array.isArray(result.thread)) {
                    parsedTweets = result.thread;
                }
            } catch (e) {
                console.warn("La respuesta de la IA parecía un hilo pero no se pudo analizar:", e);
            }
        } else {
             const conversationalCues = ["?", "puedo", "cómo", "qué", "necesitas", "ayudarte", "dime", "claro", "genial", "cuál", "sobre"];
             const isConversational = conversationalCues.some(cue => assistantResponse.toLowerCase().includes(cue));
             if (!isConversational) {
                 parsedTweets = [assistantResponse];
             }
        }

        if (parsedTweets.length > 0) {
            setTweets(parsedTweets.map((content, i) => ({
                id: `tweet-${Date.now()}-${i}`,
                content,
                media: null,
                isLoadingMedia: false,
                isCopied: false,
                isRegenerating: false,
            })));
        }

    } catch (error) {
       const errorMessage = error instanceof Error ? error.message : "Ocurrió un error desconocido.";
       setChatMessages(prev => [...prev, { author: 'ai', content: `Lo siento, ocurrió un error: ${errorMessage}` }]);
    } finally {
        setIsChatLoading(false);
    }
  };

  const handleCopy = (text: string, index: number) => {
    navigator.clipboard.writeText(text).then(() => {
      setTweets(prev => prev.map((t, i) => i === index ? {...t, isCopied: true} : t));
      setTimeout(() => {
        setTweets(prev => prev.map((t, i) => i === index ? {...t, isCopied: false} : t));
      }, 2000);
    });
  };

  const handleRegenerateTweet = async (index: number) => {
    const originalTweet = tweets[index];
    if (!originalTweet || originalTweet.content.trim() === '') return;

    setTweets(prev => prev.map((t, i) => i === index ? { ...t, isRegenerating: true } : t));

    try {
        const regeneratedContent = await regenerateTweet(originalTweet.content);
        setTweets(prev => prev.map((t, i) => i === index ? { ...t, content: regeneratedContent, isRegenerating: false } : t));
    } catch (error) {
        console.error("Error al regenerar el tuit:", error);
        setTweets(prev => prev.map((t, i) => i === index ? { ...t, isRegenerating: false } : t));
    }
  };

  const handleDeleteTweet = (index: number) => {
    if (tweets.length === 1) {
      setTweets([{ id: `tweet-0`, content: '', media: null, isLoadingMedia: false, isCopied: false, isRegenerating: false }]);
    } else {
      setTweets(prevTweets => prevTweets.filter((_, i) => i !== index));
    }
  };

  const handleStartNew = () => {
    setTweets([{ id: `tweet-0`, content: '', media: null, isLoadingMedia: false, isCopied: false, isRegenerating: false }]);
    setChatSession(createContentChatSession(brandVoiceProfile || undefined));
    setChatMessages([
      { author: 'ai', content: "¡Listo para una nueva creación! ¿Qué tienes en mente?" }
    ]);
  };

  const openMediaPromptModal = async (type: 'image' | 'video', index: number) => {
    const existingMedia = tweets[index].media;
    const isEdit = !!existingMedia && existingMedia.type === 'image' && type === 'image';

    setMediaGenerationTarget({ type, index, isEdit });
    const tweetContent = tweets[index]?.content?.trim() || '';

    setMediaPrompt(''); 
    setMediaAspectRatio('1:1');
    setIsMediaPromptModalOpen(true);
    setIsGeneratingMediaPrompt(true);

    try {
        const creativePrompt = await generateCreativeMediaPrompt(tweetContent, type, brandVoiceProfile || undefined, isEdit);
        setMediaPrompt(creativePrompt);
    } catch (error) {
        console.error("Failed to generate creative prompt:", error);
        setMediaPrompt(tweetContent);
    } finally {
        setIsGeneratingMediaPrompt(false);
    }
  };

  const closeMediaPromptModal = () => {
    setIsMediaPromptModalOpen(false);
    setMediaPrompt('');
    setMediaGenerationTarget(null);
    setIsGeneratingMediaPrompt(false);
  };

  const handleConfirmMediaGeneration = () => {
    if (!mediaGenerationTarget || !mediaPrompt) return;
    const { type, index, isEdit } = mediaGenerationTarget;
    handleGenerateMedia(type, mediaPrompt, index, { aspectRatio: mediaAspectRatio, isEdit });
    closeMediaPromptModal();
  };

  const handleGenerateMedia = useCallback(async (
    type: 'image' | 'video', 
    mediaPrompt: string, 
    tweetIndex: number,
    options: { aspectRatio?: string, isEdit?: boolean } = {}
  ) => {
    tweetPreviewRefs.current[tweetIndex]?.scrollIntoView({ behavior: 'smooth', block: 'center' });

    const existingMediaUrl = tweets[tweetIndex].media?.url;
    setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, isLoadingMedia: true } : t));
    setIsLoading(true);

    try {
        if (type === 'image') {
            const steps = options.isEdit ? ['Analizando imagen original', 'Aplicando edición', 'Renderizando', '¡Listo!'] : ['Componiendo prompt', 'Generando píxeles', 'Renderizando imagen', '¡Listo!'];
            setGenerationStatus({ title: options.isEdit ? 'Editando Imagen...' : 'Generando Imagen...', steps, currentStep: 0, error: null });

            let referenceImages: { data: string; mimeType: string }[] = [];
            if (options.isEdit && existingMediaUrl && existingMediaUrl.startsWith('data:')) {
                referenceImages.push({ data: existingMediaUrl.split(',')[1], mimeType: 'image/jpeg' });
            }

            const { images } = await generateImage(mediaPrompt, options.aspectRatio, referenceImages);
            if (images && images.length > 0) {
                setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, media: { type, url: `data:image/jpeg;base64,${images[0]}` } } : t));
            } else {
                throw new Error("La IA no devolvió ninguna imagen.");
            }
        } else {
            const videoSteps = ['Iniciando', 'Procesando IA', 'Generando fotogramas', 'Finalizando video', '¡Listo!'];
            setGenerationStatus({ title: 'Generando Video...', steps: videoSteps, currentStep: 0, error: null });

            const onProgress = (message: string) => {
              setGenerationStatus(prev => {
                  if (!prev) return null;
                  let currentStep = prev.currentStep;
                  if (message.includes('🤖')) currentStep = 1;
                  else if (message.includes('⏳')) currentStep = 2;
                  else if (message.includes('✅')) currentStep = 3;
                  else if (message.includes('🎉')) currentStep = 4;
                  return { ...prev, currentStep };
              });
            };
            const mediaUrl = await generateVideo(mediaPrompt, options.aspectRatio, onProgress);
            setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, media: { type, url: mediaUrl } } : t));
        }
    } catch (error) {
        const message = error instanceof Error ? error.message : String(error);
        setGenerationStatus(prev => prev ? { ...prev, error: message } : null);
    } finally {
        setIsLoading(false);
        setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, isLoadingMedia: false } : t));
        setTimeout(() => setGenerationStatus(null), 5000);
    }
  }, [tweets]);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    if (mediaTargetIndex === null) return;
    const tweetIndex = mediaTargetIndex;
    const file = event.target.files?.[0];
    if (!file) return;

    const mediaUrl = URL.createObjectURL(file);
    const mediaType = file.type.startsWith('image/') ? 'image' : 'video';

    setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, media: { type: mediaType, url: mediaUrl } } : t));
    setMediaTargetIndex(null);
    if(event.target) event.target.value = '';
  };

  const handleRemoveMedia = (tweetIndex: number) => {
    setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, media: null } : t));
  };

 return (
    <div className="w-full animate-fade-in">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 max-w-7xl mx-auto">
            <div className="flex flex-col gap-8 self-start">
                <div className="w-full flex flex-col items-center gap-6">
                    <header className="w-full max-w-7xl flex justify-between items-center px-4">
                        <div className="flex items-center justify-center gap-3">
                            <LogoIcon className="h-8 w-8"/>
                            <h1 className="text-xl font-bold">Content Studio</h1>
                        </div>
                        <button onClick={() => setIsBrandVoiceModalOpen(true)} className="flex items-center gap-2 px-3 py-1.5 rounded-full text-sm font-semibold transition-colors border-2 border-text-primary bg-bg-primary text-text-primary">
                            <SparklesIcon className="h-5 w-5 text-accent-secondary"/>
                            <span>Voz de Marca</span>
                        </button>
                    </header>
                    <div className="w-full max-w-3xl">
                        <ChatHistory messages={chatMessages} onSendMessage={handleSendMessage} isLoading={isChatLoading} fileToBase64={fileToBase64} />
                    </div>
                </div>
            </div>

            <div className="lg:sticky lg:top-28 h-fit max-h-[calc(100vh-8rem)]">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-2xl font-bold text-text-primary">Vista Previa</h3>
                    <button onClick={handleStartNew} className="flex items-center gap-2 px-4 py-2 rounded-full text-sm font-bold transition-colors bg-bg-secondary border-2 border-text-primary text-text-secondary hover:bg-border-primary hover:text-text-primary">
                        <PlusIcon className="h-5 w-5" /> Nueva Creación
                    </button>
                </div>
                <div className="overflow-y-auto pr-2 max-h-[calc(100vh-12rem)]">
                    <div className="space-y-4">
                      {tweets.map((tweet, index) => (
                          <div key={tweet.id} ref={el => { tweetPreviewRefs.current[index] = el; }}>
                              <TweetPreview
                                  tweet={{ id: tweet.id, content: tweet.content, author: DEFAULT_USER, media: tweet.media || undefined, public_metrics: { like_count: 0, retweet_count: 0, impression_count: 0, reply_count: 0, quote_count: 0 }, created_at: new Date().toISOString(), }}
                                  editableTweet={tweet}
                                  isGenerating={isLoading}
                                  onCopy={() => handleCopy(tweet.content, index)}
                                  onGenerateMedia={(type) => openMediaPromptModal(type, index)}
                                  onUploadMedia={() => { setMediaTargetIndex(index); fileInputRef.current?.click(); }}
                                  onRemoveMedia={() => handleRemoveMedia(index)}
                                  onTweetChange={(value) => handleTweetChange(index, value)}
                                  onRegenerate={() => handleRegenerateTweet(index)}
                                  onDeleteTweet={() => handleDeleteTweet(index)}
                              />
                          </div>
                      ))}
                    </div>
