export const generateTweetThread = async (
    prompt: string,
    source?: Source,
    audience?: string,
    file?: FilePart,
    tone?: string,
    format?: string,
    keywords?: string,
    brandVoice?: BrandVoiceProfile,
    useWebSearch?: boolean
): Promise<string[]> => {
    try {
        const ai = getGeminiClient();
        const systemInstruction = getSystemInstructionThread(audience, tone, format, keywords, brandVoice);
        const parts: any[] = [];
        if (file) parts.push(prepareFilePart(file));
        parts.push({ text: prompt });

        const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: TEXT_MODEL,
            contents: { parts },
            config: {
                systemInstruction,
                responseMimeType: 'application/json',
                tools: (useWebSearch || prompt.toLowerCase().includes('investiga')) ? [{ googleSearch: {} }] : undefined,
            }
        }));

        let jsonStr = (response.text || '').trim();
        const jsonMatch = jsonStr.match(/```json\n?([\s\S]*?)\n?```/);
        if (jsonMatch && jsonMatch[1]) jsonStr = jsonMatch[1];
        else {
             const firstBrace = jsonStr.indexOf('{');
             const lastBrace = jsonStr.lastIndexOf('}');
             if (firstBrace !== -1) jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
        }

        const result = JSON.parse(jsonStr);
        if (result.thread && Array.isArray(result.thread)) return result.thread;
        throw new Error("Formato de hilo inválido.");

    } catch (error) {
        handleGenerationError(error, 'hilo de tuits');
        return [];
    }
};

