                id: `tweet-${Date.now()}-${i}`,
                content,
                media: null,
                isLoadingMedia: false,
                isCopied: false,
                isRegenerating: false,
            })));
        }

    } catch (error) {
       const errorMessage = error instanceof Error ? error.message : "Ocurrió un error desconocido.";
       setChatMessages(prev => [...prev, { author: 'ai', content: `Lo siento, ocurrió un error: ${errorMessage}` }]);
    } finally {
        setIsChatLoading(false);
    }
  };

  const handleCopy = (text: string, index: number) => {
    navigator.clipboard.writeText(text).then(() => {
      setTweets(prev => prev.map((t, i) => i === index ? {...t, isCopied: true} : t));
      setTimeout(() => {
        setTweets(prev => prev.map((t, i) => i === index ? {...t, isCopied: false} : t));
      }, 2000);
    });
  };

  const handleRegenerateTweet = async (index: number) => {
    const originalTweet = tweets[index];
    if (!originalTweet || originalTweet.content.trim() === '') return;

    setTweets(prev => prev.map((t, i) => i === index ? { ...t, isRegenerating: true } : t));

    try {
        const regeneratedContent = await regenerateTweet(originalTweet.content);
        setTweets(prev => prev.map((t, i) => i === index ? { ...t, content: regeneratedContent, isRegenerating: false } : t));
    } catch (error) {
        console.error("Error al regenerar el tuit:", error);
        setTweets(prev => prev.map((t, i) => i === index ? { ...t, isRegenerating: false } : t));
    }
  };

  const handleDeleteTweet = (index: number) => {
    if (tweets.length === 1) {
      setTweets([{ id: `tweet-0`, content: '', media: null, isLoadingMedia: false, isCopied: false, isRegenerating: false }]);
    } else {
      setTweets(prevTweets => prevTweets.filter((_, i) => i !== index));
    }
  };

  const handleStartNew = () => {
    setTweets([{ id: `tweet-0`, content: '', media: null, isLoadingMedia: false, isCopied: false, isRegenerating: false }]);
    setChatSession(createContentChatSession(brandVoiceProfile || undefined));
    setChatMessages([
      { author: 'ai', content: "¡Listo para una nueva creación! ¿Qué tienes en mente?" }
    ]);
  };

  const openMediaPromptModal = async (type: 'image' | 'video', index: number) => {
    const existingMedia = tweets[index].media;
    const isEdit = !!existingMedia && existingMedia.type === 'image' && type === 'image';

    setMediaGenerationTarget({ type, index, isEdit });
    const tweetContent = tweets[index]?.content?.trim() || '';

    setMediaPrompt(''); 
    setMediaAspectRatio('1:1');
    setIsMediaPromptModalOpen(true);
    setIsGeneratingMediaPrompt(true);

    try {
        const creativePrompt = await generateCreativeMediaPrompt(tweetContent, type, brandVoiceProfile || undefined, isEdit);
        setMediaPrompt(creativePrompt);
    } catch (error) {
        console.error("Failed to generate creative prompt:", error);
        setMediaPrompt(tweetContent);
    } finally {
        setIsGeneratingMediaPrompt(false);
    }
  };

  const closeMediaPromptModal = () => {
    setIsMediaPromptModalOpen(false);
    setMediaPrompt('');
    setMediaGenerationTarget(null);
    setIsGeneratingMediaPrompt(false);
  };

  const handleConfirmMediaGeneration = () => {
    if (!mediaGenerationTarget || !mediaPrompt) return;
    const { type, index, isEdit } = mediaGenerationTarget;
    handleGenerateMedia(type, mediaPrompt, index, { aspectRatio: mediaAspectRatio, isEdit });
    closeMediaPromptModal();
  };

  const handleGenerateMedia = useCallback(async (
    type: 'image' | 'video', 
    mediaPrompt: string, 
    tweetIndex: number,
    options: { aspectRatio?: string, isEdit?: boolean } = {}
  ) => {
    tweetPreviewRefs.current[tweetIndex]?.scrollIntoView({ behavior: 'smooth', block: 'center' });

    const existingMediaUrl = tweets[tweetIndex].media?.url;
    setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, isLoadingMedia: true } : t));
    setIsLoading(true);

    try {
        if (type === 'image') {
            const steps = options.isEdit ? ['Analizando imagen original', 'Aplicando edición', 'Renderizando', '¡Listo!'] : ['Componiendo prompt', 'Generando píxeles', 'Renderizando imagen', '¡Listo!'];
            setGenerationStatus({ title: options.isEdit ? 'Editando Imagen...' : 'Generando Imagen...', steps, currentStep: 0, error: null });

            let referenceImages: { data: string; mimeType: string }[] = [];
            if (options.isEdit && existingMediaUrl && existingMediaUrl.startsWith('data:')) {
                referenceImages.push({ data: existingMediaUrl.split(',')[1], mimeType: 'image/jpeg' });
            }

            const { images } = await generateImage(mediaPrompt, options.aspectRatio, referenceImages);
            if (images && images.length > 0) {
                setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, media: { type, url: `data:image/jpeg;base64,${images[0]}` } } : t));
            } else {
                throw new Error("La IA no devolvió ninguna imagen.");
            }
        } else {
            const videoSteps = ['Iniciando', 'Procesando IA', 'Generando fotogramas', 'Finalizando video', '¡Listo!'];
            setGenerationStatus({ title: 'Generando Video...', steps: videoSteps, currentStep: 0, error: null });

            const onProgress = (message: string) => {
              setGenerationStatus(prev => {
                  if (!prev) return null;
                  let currentStep = prev.currentStep;
                  if (message.includes('🤖')) currentStep = 1;
                  else if (message.includes('⏳')) currentStep = 2;
                  else if (message.includes('✅')) currentStep = 3;
                  else if (message.includes('🎉')) currentStep = 4;
                  return { ...prev, currentStep };
              });
            };
            const mediaUrl = await generateVideo(mediaPrompt, options.aspectRatio, onProgress);
            setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, media: { type, url: mediaUrl } } : t));
        }
    } catch (error) {
        const message = error instanceof Error ? error.message : String(error);
        setGenerationStatus(prev => prev ? { ...prev, error: message } : null);
    } finally {
        setIsLoading(false);
        setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, isLoadingMedia: false } : t));
        setTimeout(() => setGenerationStatus(null), 5000);
    }
  }, [tweets]);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    if (mediaTargetIndex === null) return;
    const tweetIndex = mediaTargetIndex;
    const file = event.target.files?.[0];
    if (!file) return;

    const mediaUrl = URL.createObjectURL(file);
    const mediaType = file.type.startsWith('image/') ? 'image' : 'video';

    setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, media: { type: mediaType, url: mediaUrl } } : t));
    setMediaTargetIndex(null);
    if(event.target) event.target.value = '';
  };

  const handleRemoveMedia = (tweetIndex: number) => {
    setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, media: null } : t));
  };

 return (
    <div className="w-full animate-fade-in">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 max-w-7xl mx-auto">
            <div className="flex flex-col gap-8 self-start">
                <div className="w-full flex flex-col items-center gap-6">
                    <header className="w-full max-w-7xl flex justify-between items-center px-4">
                        <div className="flex items-center justify-center gap-3">
                            <LogoIcon className="h-8 w-8"/>
                            <h1 className="text-xl font-bold">Content Studio</h1>
                        </div>
                        <button onClick={() => setIsBrandVoiceModalOpen(true)} className="flex items-center gap-2 px-3 py-1.5 rounded-full text-sm font-semibold transition-colors border-2 border-text-primary bg-bg-primary text-text-primary">
                            <SparklesIcon className="h-5 w-5 text-accent-secondary"/>
                            <span>Voz de Marca</span>
                        </button>
                    </header>
                    <div className="w-full max-w-3xl">
                        <ChatHistory messages={chatMessages} onSendMessage={handleSendMessage} isLoading={isChatLoading} fileToBase64={fileToBase64} />
                    </div>
                </div>
            </div>

            <div className="lg:sticky lg:top-28 h-fit max-h-[calc(100vh-8rem)]">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-2xl font-bold text-text-primary">Vista Previa</h3>
                    <button onClick={handleStartNew} className="flex items-center gap-2 px-4 py-2 rounded-full text-sm font-bold transition-colors bg-bg-secondary border-2 border-text-primary text-text-secondary hover:bg-border-primary hover:text-text-primary">
                        <PlusIcon className="h-5 w-5" /> Nueva Creación
                    </button>
                </div>
                <div className="overflow-y-auto pr-2 max-h-[calc(100vh-12rem)]">
                    <div className="space-y-4">
                      {tweets.map((tweet, index) => (
                          <div key={tweet.id} ref={el => { tweetPreviewRefs.current[index] = el; }}>
                              <TweetPreview
                                  tweet={{ id: tweet.id, content: tweet.content, author: DEFAULT_USER, media: tweet.media || undefined, public_metrics: { like_count: 0, retweet_count: 0, impression_count: 0, reply_count: 0, quote_count: 0 }, created_at: new Date().toISOString(), }}
                                  editableTweet={tweet}
                                  isGenerating={isLoading}
                                  onCopy={() => handleCopy(tweet.content, index)}
                                  onGenerateMedia={(type) => openMediaPromptModal(type, index)}
                                  onUploadMedia={() => { setMediaTargetIndex(index); fileInputRef.current?.click(); }}
                                  onRemoveMedia={() => handleRemoveMedia(index)}
                                  onTweetChange={(value) => handleTweetChange(index, value)}
                                  onRegenerate={() => handleRegenerateTweet(index)}
                                  onDeleteTweet={() => handleDeleteTweet(index)}
                              />
                          </div>
                      ))}
                    </div>
                    {tweets.length > 0 && tweets.some(t => t.content) && (
                      <button onClick={addTweetToThread} className="mt-4 text-accent-primary font-semibold hover:underline self-start"> + Añadir al Hilo </button>
                  )}
                </div>
            </div>
        </div>

        {generationStatus && <GenerationStatus title={generationStatus.title} steps={generationStatus.steps} currentStepIndex={generationStatus.currentStep} error={generationStatus.error} />}
        <BrandVoiceModal isOpen={isBrandVoiceModalOpen} onClose={() => setIsBrandVoiceModalOpen(false)} onSave={handleSaveBrandVoice} />
        <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept="image/*,video/*" />

        {isMediaPromptModalOpen && (
            <div className="fixed inset-0 bg-bg-primary/80 backdrop-blur-sm flex items-center justify-center p-4 z-50 animate-fade-in">
                <div className="bg-bg-secondary border border-border-primary rounded-xl p-6 w-full max-w-lg relative shadow-2xl shadow-black/50">
                    <h2 className="text-xl font-bold mb-4">{mediaGenerationTarget?.isEdit ? 'Instrucciones de Edición' : `Revisar Prompt de ${mediaGenerationTarget?.type === 'image' ? 'Imagen' : 'Video'}`}</h2>

                    <div className="relative">
                        <textarea
                            value={mediaPrompt}
                            onChange={(e) => setMediaPrompt(e.target.value)}
                            placeholder={isGeneratingMediaPrompt ? "Generando prompt creativo..." : "Introduce o edita el prompt..."}
                            className={`w-full bg-bg-primary border border-border-primary rounded-lg p-3 focus:ring-2 focus:ring-accent-primary focus:outline-none transition mb-4 min-h-[120px] ${isGeneratingMediaPrompt ? 'opacity-50' : 'opacity-100'}`}
                            rows={5}
                            disabled={isGeneratingMediaPrompt}
                        />
                        {isGeneratingMediaPrompt && (
                            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                <div className="flex flex-col items-center gap-2">
                                    <LoaderIcon className="h-8 w-8 text-accent-primary" />
                                    <span className="text-xs font-bold text-accent-primary animate-pulse">Pensando...</span>
                                </div>
                            </div>
                        )}
                    </div>

                    {!isGeneratingMediaPrompt && (
                        <>
                            {mediaGenerationTarget?.type === 'image' && (
                                <div className="mb-4">
                                    <label className="text-sm font-semibold text-text-secondary mb-2 block">Relación de Aspecto</label>
                                    <div className="flex gap-2">
                                        {['1:1', '16:9', '9:16', '4:3'].map(ratio => (
                                            <button key={ratio} onClick={() => setMediaAspectRatio(ratio)} className={`px-3 py-1 rounded-full text-xs font-bold border transition-colors ${mediaAspectRatio === ratio ? 'bg-accent-primary text-white border-accent-primary' : 'bg-transparent text-text-secondary border-slate-600 hover:border-slate-400'}`}>
                                                {ratio}
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            )}

                            <div className="flex justify-end gap-3 mt-6">
                                <button onClick={closeMediaPromptModal} className="ai-button bg-bg-primary hover:bg-border-primary/50 text-text-primary px-6">Cancelar</button>
                                <button onClick={handleConfirmMediaGeneration} disabled={!mediaPrompt} className="ai-button bg-accent-primary hover:opacity-90 text-white px-6">
                                    {mediaGenerationTarget?.isEdit ? 'Aplicar Edición' : 'Crear Medio'}
                                </button>
                            </div>
                        </>
                    )}
                </div>
            </div>
        )}

        <style>{`
            .ai-button { display: flex; align-items: center; justify-content: center; gap: 0.5rem; padding: 0.75rem; border-radius: 9999px; font-weight: bold; transition: all 0.2s; border: 2px solid #0f172a; }
            .ai-button:disabled { opacity: 0.5; cursor: not-allowed; }
            .animate-fade-in { animation: fadeIn 0.5s ease-out forwards; }
            @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
        `}</style>
    </div>
  );
};

export default Dashboard;

