    }
  }, []);

  useEffect(() => {
    setChatSession(createContentChatSession(brandVoiceProfile || undefined, targetAudience));
  }, [brandVoiceProfile, targetAudience]);

  const handleSaveBrandVoice = (profile: BrandVoiceProfile) => {
    setBrandVoiceProfile(profile);
    localStorage.setItem('twixai-brand-voice', JSON.stringify(profile));
  };

  const handleTweetChange = (index: number, value: string) => {
    const newTweets = [...tweets];
    newTweets[index].content = value;
    setTweets(newTweets);
  };

  const addTweetToThread = () => {
    setTweets([...tweets, { id: `tweet-${Date.now()}`, content: '', media: null, isLoadingMedia: false, isCopied: false, isRegenerating: false }]);
  };

  const handleGenerateThread = async () => {
      const lastMessage = chatMessages[chatMessages.length - 1];
      if (isChatLoading) return;

      setIsChatLoading(true);
      try {
          const thread = await generateTweetThread(
              lastMessage.author === 'ai' ? `Basado en esto: ${lastMessage.content}` : lastMessage.content,
              targetAudience,
              brandVoiceProfile || undefined
          );

          if (thread && thread.length > 0) {
              setTweets(thread.map((content, i) => ({
                  id: `tweet-${Date.now()}-${i}`,
                  content,
                  media: null,
                  isLoadingMedia: false,
                  isCopied: false,
                  isRegenerating: false,
              })));
              setChatMessages(prev => [...prev, { author: 'ai', content: `Hilo de ${thread.length} tuits generado para ${targetAudience || 'tu audiencia'}. ¿Qué te parece?` }]);
          }
      } catch (error) {
          console.error("Error generating thread:", error);
          setChatMessages(prev => [...prev, { author: 'ai', content: "Lo siento, hubo un error al intentar estructurar el hilo." }]);
      } finally {
          setIsChatLoading(false);
      }
  };

  const handleSendMessage = async (message: string, file?: { data: string; mimeType: string; name: string }) => {
    if ((!message || message.trim() === '') && !file) return;

    const userMessageContent = file ? `${message}\n\n[Archivo adjunto: ${file.name}]` : message;
    const userMessage: ChatMessage = { author: 'user', content: userMessageContent };
    setChatMessages(prev => [...prev, userMessage]);
    setIsChatLoading(true);

    try {
        if (!chatSession) throw new Error("La sesión de chat no está inicializada.");

        const parts: any[] = [{ text: `${message}${targetAudience ? ` (Optimiza para: ${targetAudience})` : ''}` }];
        if (file) {
            parts.push({ inlineData: { mimeType: file.mimeType, data: file.data } });
        }

        const response = await chatSession.sendMessage({ message: parts });
        const assistantResponse = (response.text || '').trim();

        setChatMessages(prev => [...prev, { author: 'ai', content: assistantResponse }]);

        if (assistantResponse.includes('"thread":')) {
            try {
                const result = JSON.parse(assistantResponse.match(/\{[\s\S]*\}/)?.[0] || '{}');
                if (result.thread) {
                    setTweets(result.thread.map((content: string, i: number) => ({
                        id: `tweet-${Date.now()}-${i}`,
                        content,
                        media: null,
                        isLoadingMedia: false,
                        isCopied: false,
                        isRegenerating: false,
                    })));
                    return;
                }
            } catch (e) { console.warn("Failed to parse automatic thread", e); }
        }

        const conversationalCues = ["?", "puedo", "cómo", "qué", "ayudarte", "dime", "claro"];
        const isConversational = conversationalCues.some(cue => assistantResponse.toLowerCase().includes(cue));

        if (!isConversational && assistantResponse.length > 5) {
            setTweets([{
                id: `tweet-${Date.now()}`,
                content: assistantResponse,
                media: null,
                isLoadingMedia: false,
                isCopied: false,
                isRegenerating: false,
            }]);
        }
