    setTweets([...tweets, '']);
  };

  // FIX: Updated handleGenerate to call service functions with the correct number of arguments.
  const handleGenerate = useCallback(async (type: 'tweet' | 'thread') => {
    setIsLoading(prev => ({ ...prev, [type]: true }));
    let sourceToUse: Source | undefined = undefined;
    if (createMode === CreateMode.Link && linkUrl) {
        sourceToUse = { web: { uri: linkUrl, title: 'External Link' } };
    }
    const audienceToUse = audience.trim() || undefined;

    if (type === 'tweet') {
        const result = await generateTweet(prompt, sourceToUse, audienceToUse);
        setTweets([result]);
    } else {
        const results = await generateTweetThread(prompt, sourceToUse, audienceToUse);
        setTweets(results.length > 0 ? results : ['']);
    }
    setIsLoading(prev => ({ ...prev, [type]: false }));
  }, [prompt, createMode, audience, linkUrl]);

  const handleFetchLink = async () => {
      if (!linkUrl) return;
      setIsFetchingLink(true);
      const summary = await summarizeUrl(linkUrl);
      setPrompt(summary);
      setIsFetchingLink(false);
  }

  const handleGenerateMedia = useCallback(async (type: 'image' | 'video') => {
      setIsLoading(prev => ({ ...prev, [type]: true }));
      setMedia(null);
      setVideoProgress('');
      try {
          if (type === 'image') {
              const { images } = await generateImage(prompt);
              setMedia({ type: 'image', url: `data:image/jpeg;base64,${images[0]}` });
          } else {
              // FIX: The second argument to generateVideo must be an aspect ratio.
              // The style 'cinematic' is added to the prompt. A 16:9 aspect ratio is assumed as a default.
              const videoUrl = await generateVideo(`${prompt}, cinematic style`, '16:9', setVideoProgress);
              setMedia({ type: 'video', url: videoUrl });
          }
